    fn test_orphans_panel_formatting() {
        let orphans = vec![
            make_issue("orphan-1", "Fix auth bug", Priority::HIGH),
            make_issue("orphan-2", "Update docs", Priority::MEDIUM),
        ];
        let ctx = OutputContext::rich();
        let output = format_orphans(&orphans, &ctx);
        assert!(output.contains("orphan-1"));
        assert!(output.contains("orphan-2"));
        assert!(output.contains("12") || output.contains("2")); // count
    }

    #[test]
